import "@/App.css";
import React, { Suspense, useEffect } from "react";
import { BrowserRouter, Routes, Route, useLocation } from "react-router-dom";
import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { MarketProvider } from "@/lib/MarketContext";
import { Toaster } from "@/components/ui/sonner";
import CompareTray from "@/components/landing/CompareTray";
import DetailDrawer from "@/components/landing/DetailDrawer";
import CommandPalette from "@/components/landing/CommandPalette";
import KeyboardHelpModal from "@/components/landing/KeyboardHelpModal";
import BackToTop from "@/components/landing/BackToTop";
import InstallPrompt from "@/components/landing/InstallPrompt";
import VersionPrompt from "@/components/landing/VersionPrompt";
import ErrorBoundary, { InlineFallback } from "@/components/ErrorBoundary";
import PageSkeleton from "@/components/PageSkeleton";

const LandingPage = React.lazy(() => import("@/pages/LandingPage"));
const ListingsPage = React.lazy(() => import("@/pages/ListingsPage"));
const FavoritesPage = React.lazy(() => import("@/pages/FavoritesPage"));
const ComparePage = React.lazy(() => import("@/pages/ComparePage"));
const SellersPage = React.lazy(() => import("@/pages/SellersPage"));
const ShopsPage = React.lazy(() => import("@/pages/ShopsPage"));
const SellerDetail = React.lazy(() => import("@/pages/SellerDetail"));
const LegalPage = React.lazy(() => import("@/pages/LegalPage"));
const NotFoundPage = React.lazy(() => import("@/pages/NotFoundPage"));
const ItemDetail = React.lazy(() => import("@/pages/ItemDetail"));
const LookupPage = React.lazy(() => import("@/pages/LookupPage"));
const DashboardPage = React.lazy(() => import("@/pages/Dashboard"));
const AlertsPage = React.lazy(() => import("@/pages/AlertsPage"));
const TradingHistoryPage = React.lazy(() => import("@/pages/TradingHistory"));

function ScrollToTop() {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo({ top: 0, left: 0, behavior: "instant" });
  }, [pathname]);
  return null;
}

function AnimatedRoutes() {
  const location = useLocation();
  const prefersReduced = useReducedMotion();
  if (prefersReduced) {
    return (
      <Suspense fallback={<PageSkeleton />}>
        <Routes location={location}>
          <Route path="/" element={<LandingPage />} />
          <Route path="/listings" element={<ListingsPage />} />
          <Route path="/favorites" element={<FavoritesPage />} />
          <Route path="/compare" element={<ComparePage />} />
          <Route path="/shops" element={<ShopsPage />} />
<Route path="/item/:key" element={<ItemDetail />} />
           <Route path="/lookup" element={<LookupPage />} />
           <Route path="/sellers" element={<SellersPage />} />
<Route path="/sellers/:name" element={<SellerDetail />} />
           <Route path="/legal" element={<LegalPage />} />
<Route path="/dashboard" element={<DashboardPage />} />
            <Route path="/alerts" element={<AlertsPage />} />
            <Route path="/trading-history" element={<TradingHistoryPage />} />
            <Route path="*" element={<NotFoundPage />} />
        </Routes>
      </Suspense>
    );
  }
  return (
    <AnimatePresence mode="wait">
      <motion.div
        key={location.pathname}
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -4 }}
        transition={{ duration: 0.3, ease: [0.16, 1, 0.3, 1] }}
      >
        <Suspense fallback={<PageSkeleton />}>
          <Routes location={location}>
            <Route path="/" element={<LandingPage />} />
            <Route path="/listings" element={<ListingsPage />} />
            <Route path="/favorites" element={<FavoritesPage />} />
            <Route path="/compare" element={<ComparePage />} />
            <Route path="/shops" element={<ShopsPage />} />
<Route path="/item/:key" element={<ItemDetail />} />
             <Route path="/lookup" element={<LookupPage />} />
             <Route path="/sellers" element={<SellersPage />} />
<Route path="/sellers/:name" element={<SellerDetail />} />
             <Route path="/legal" element={<LegalPage />} />
<Route path="/dashboard" element={<DashboardPage />} />
              <Route path="/alerts" element={<AlertsPage />} />
              <Route path="/trading-history" element={<TradingHistoryPage />} />
              <Route path="*" element={<NotFoundPage />} />
          </Routes>
        </Suspense>
      </motion.div>
    </AnimatePresence>
  );
}

function RoutedErrorBoundary({ children }) {
  const { pathname } = useLocation();
  return (
    <ErrorBoundary key={pathname} resetKey={pathname}>
      {children}
    </ErrorBoundary>
  );
}

function App() {
  return (
    <div className="App">
      <BrowserRouter basename={process.env.PUBLIC_URL}>
        <ScrollToTop />
        <MarketProvider>
          <RoutedErrorBoundary>
            <AnimatedRoutes />
          </RoutedErrorBoundary>
          <ErrorBoundary fallback={<InlineFallback message="Detail panel failed to load. Close and reopen." />}>
            <DetailDrawer />
          </ErrorBoundary>
          <ErrorBoundary fallback={null}>
            <CompareTray />
          </ErrorBoundary>
          <ErrorBoundary fallback={null}>
            <CommandPalette />
          </ErrorBoundary>
          <KeyboardHelpModal />
          <BackToTop />
          <InstallPrompt />
          <VersionPrompt />
          <Toaster />
        </MarketProvider>
      </BrowserRouter>
    </div>
  );
}

export default App;
